import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { DateRangeFilter, Select, dispatchAppToast, type DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatQty, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { PartnerDto, PurchaseReportRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-mua-hang';
const PAGE_ID = 'baocao-mua-hang';
const GROUP_OPTIONS = [
  { value: 'supplier', label: 'Theo NCC' },
  { value: 'material', label: 'Theo mặt hàng' },
];

const BaoCaoMuaHangPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [supplierId, setSupplierId] = useState('');
  const [groupBy, setGroupBy] = useState<'supplier' | 'material'>('supplier');
  const [partners, setPartners] = useState<PartnerDto[]>([]);
  const [rows, setRows] = useState<PurchaseReportRow[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      analyticsService
        .getPartners({ partnerType: 'Supplier', pageSize: 500 })
        .then(d => {
          if (!cancelled) setPartners(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getPurchaseReport({
        fromDate,
        toDate,
        supplierId: supplierId || undefined,
        groupBy,
      })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi tải báo cáo'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, supplierId, groupBy, dispatch]);

  const bm = groupBy === 'material';
  const tQ = rows.reduce((s, r) => s + (r.quantity ?? 0), 0);
  const tS = rows.reduce((s, r) => s + (r.subTotal ?? 0), 0);
  const tV = rows.reduce((s, r) => s + (r.vatAmount ?? 0), 0);
  const tA = rows.reduce((s, r) => s + (r.totalAmount ?? 0), 0);

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <div className={erp.field}>
            <DateRangeFilter
              label="Thời gian"
              fullWidth
              testId={`${TEST_ID}-date-range`}
              fromDate={fromDate}
              toDate={toDate}
              onChange={(v: DateRangeValue) => {
                setFromDate(v.fromDate ?? '');
                setToDate(v.toDate ?? '');
              }}
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-supplier`,
        content: (
          <div className={erp.field}>
            <Select
              label="Nhà cung cấp"
              value={supplierId}
              onChange={e => setSupplierId(e.target.value)}
              options={[
                { value: '', label: 'Tất cả NCC' },
                ...partners.map(p => ({ value: p.id, label: `${p.code} — ${p.name}` })),
              ]}
              size="small"
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-groupBy`,
        content: (
          <div className={erp.field}>
            <Select
              label="Nhóm theo"
              value={groupBy}
              onChange={e => setGroupBy(e.target.value as 'supplier' | 'material')}
              options={GROUP_OPTIONS}
              size="small"
            />
          </div>
        ),
      },
    ],
    [fromDate, toDate, supplierId, groupBy, partners],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo mua hàng"
      titleIconClass="fas fa-shopping-cart"
      loading={loading}
      hasData={rows.length > 0}
      filterItems={filterItems}
      onLoad={handleLoad}
      exportPath="/accounting/purchase-report/export-excel"
      exportParams={{ fromDate, toDate, supplierId: supplierId || undefined, groupBy }}
      exportFilename={`BaoCaoMuaHang-${fromDate}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            {bm ? (
              <>
                <th>Mã hàng</th>
                <th>Tên hàng</th>
                <th>ĐVT</th>
                <th>NCC</th>
              </>
            ) : (
              <>
                <th>NCC</th>
                <th>Mặt hàng</th>
              </>
            )}
            <th className={reportStyles.colRight}>SL</th>
            <th className={reportStyles.colRight}>Giá trị</th>
            <th className={reportStyles.colRight}>VAT</th>
            <th className={reportStyles.colRight}>Tổng</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              {bm ? (
                <>
                  <td>{r.materialCode ?? '—'}</td>
                  <td>{r.materialName}</td>
                  <td>{r.unit ?? '—'}</td>
                  <td>{r.supplierName}</td>
                </>
              ) : (
                <>
                  <td>{r.supplierName}</td>
                  <td>{r.materialName}</td>
                </>
              )}
              <td className={reportStyles.colRight}>{formatQty(r.quantity)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.subTotal)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.vatAmount)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.totalAmount)}</td>
            </tr>
          ))}
          <tr className={reportStyles.rowTotal}>
            <td colSpan={bm ? 4 : 2}>Tổng</td>
            <td className={reportStyles.colRight}>{formatQty(tQ)}</td>
            <td className={reportStyles.colRight}>{formatVnd(tS)}</td>
            <td className={reportStyles.colRight}>{formatVnd(tV)}</td>
            <td className={reportStyles.colRight}>{formatVnd(tA)}</td>
          </tr>
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoMuaHangPage;
